import 'package:firebase_crashlytics/firebase_crashlytics.dart'; import 'package:injectable/injectable.dart'; @singleton class CrashReporter { Future<void> recordError(dynamic err, StackTrace? stack, {bool fatal = false}) async { await FirebaseCrashlytics.instance.recordError(err, stack, fatal: fatal); } Future<void> log(String msg) async { await FirebaseCrashlytics.instance.log(msg); } Future<void> setUserId(String uid) async { await FirebaseCrashlytics.instance.setUserIdentifier(uid); } }